public TreeNode insertIntoMaxTree(TreeNode root, int val) {
    if (root == null || val > root.val) {
        TreeNode newNode = new TreeNode(val);
        newNode.left = root;
        return newNode;
    }
    root.right = insertIntoMaxTree(root.right, val);
    return root;
}
```


